import re, pathlib
p = pathlib.Path('/Users/gbang/Downloads/algora/workspace/969a289a-8e87-431a-b5bd-fbefd2aedb60_hld/_response.md')
md = p.read_text(encoding='utf-8')
mermaid_blocks = re.findall(r'```mermaid(.*?)```', md, re.DOTALL)

# Stricter: find ANY label text and check for the truly-breaking set, ignoring the
# quote/bracket delimiters themselves. Breaking inside-label chars: ( ) : / ; < > | { }
truly_breaking = set('():/;<>|{}')
problems = []
for bi, blk in enumerate(mermaid_blocks):
    for line in blk.splitlines():
        s = line.strip()
        # edge pipe labels: text between |"..."| or |...|
        for m in re.finditer(r'\|"([^"]*)"\|', s):
            t = m.group(1)
            for ch in t:
                if ch in truly_breaking:
                    problems.append((bi,'edge',t,ch)); break
        # node labels in [ ], [( )], [[ ]] possibly quoted
        for m in re.finditer(r'\[\[?\(?\"?([^\]\["()]*?)\"?\)?\]?\]', s):
            t = m.group(1)
            for ch in t:
                if ch in truly_breaking:
                    problems.append((bi,'node',t,ch)); break
        # curly decision node {text}
        for m in re.finditer(r'\{([^}]*)\}', s):
            t = m.group(1)
            for ch in t:
                if ch in '():/;<>|':
                    problems.append((bi,'curly',t,ch)); break

print("Real breaking-char problems:", problems if problems else "NONE")

# Also confirm flowchart TD usage and no LR-multipath
for bi, blk in enumerate(mermaid_blocks):
    first = next((l.strip() for l in blk.splitlines() if l.strip()), '')
    print(f"block {bi}: {first}")
